import {Link, useNavigate} from "react-router-dom";
import {useRef, useState} from "react";
import axios from "axios";
import isEmail from "validator/es/lib/isEmail";
import {useSelector} from "react-redux";

const required = (value) => {
    if (!value) {
        return (
            <div className="alert alert-danger">
                Trường này là bắt buộc!
            </div>
        )
    }
}

const validEmail = (value) => {
    if (!isEmail(value)) {
        return (
            <div className="alert alert-danger">
                Đây không phải là một Email hợp lệ.
            </div>
        )
    }
}

const validUsername = (value) => {
    if (value.length < 3 || value.length > 20) {
        return (
            <div className="alert alert-danger">
                Tên người dùng phải có từ 3 đến 20 ký tự.
            </div>
        )
    }
}

const validPassword = (value) => {
    if (value.length < 6 || value.length > 40) {
        return (
            <div className="alert alert-danger">
                Mật khẩu phải dài từ 6 đến 40 ký tự.
            </div>
        )
    }
}

const RegisterForm = () => {
    const form = useRef();
    const checkBtn = useRef();

    const [username, setUsername] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [successful, setSuccessful] = useState(false);

    const {message} = useSelector

    const [formData, setFormData] = useState({
        username: '',
        email: '',
        password: '',
        confirmPassword: ''
    })
    const [error, setError] = useState('')
    const navigate = useNavigate();
    const handlePasswordChange = (e) => {
        const value = e.target.value;
        setFormData({
            ...formData,
            password: value
        });
        if (value.length > 0 && value.length < 6) {
            e.target.setCustomValidity(`Please lengthen this text to 6 
            characters or more (you are currently using ${value.length} character${value.length > 1 ? 's' : ''}).`)
        } else {
            e.target.setCustomValidity("");
        }
    }
    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    }
    const handleSubmit = async (e) => {
        e.preventDefault();
        if (formData.password !== formData.confirmPassword) {
            alert("Mật khẩu không khớp.")
            return;
        }
        try {
            const response = await axios.post('http://localhost:8080/api/auth/signup', {
                username: formData.username,
                email: formData.email,
                password: formData.password
            })
            if (response.status === 200) {
                localStorage.setItem('isLoggedIn', 'true');
                alert("Đăng ký thành công!.")
                navigate('/');
            } else {
                setError("Đăng ký thất bại!.")
            }
        } catch (error) {
            setError("Có lỗi xảy ra, vui lòng thử lại.")
        }
    }
    return (
        <div className="container bg-dark p-5">
            <span> <Link to="/" className="text-decoration-none">Trang chủ </Link>
                <i className="bi bi-chevron-double-right"></i>
                <span className="text-warning"> Đăng ký</span>
            </span>
            <form onSubmit={handleSubmit} className="container p-4">
                <h2 className="text-warning text-center">Đăng ký</h2>
                <div className="mb-3 mt-3">
                    <label htmlFor="username">Tên tài khoản:</label>
                    <input
                        type="text"
                        className="form-control"
                        id="email"
                        placeholder="Enter username"
                        value={formData.username}
                        onChange={handleChange}
                        name="username"/>
                </div>
                <div className="mb-3 mt-3">
                    <label htmlFor="email">Email:</label>
                    <input
                        type="email"
                        className="form-control"
                        id="email"
                        placeholder="Enter email"
                        name="email"
                        onChange={handleChange}
                        value={formData.email}
                        required/>
                </div>
                <div className="mb-3">
                    <label htmlFor="pwd">Mật khẩu:</label>
                    <input
                        type="password"
                        className="form-control"
                        id="pwd"
                        placeholder="Enter password"
                        name="password"
                        value={formData.password}
                        onChange={handlePasswordChange}
                        required/>
                </div>
                <div className="mb-3">
                    <label htmlFor="rpwd">Nhập lại mật khẩu:</label>
                    <input
                        type="password"
                        className="form-control"
                        id="rpwd"
                        placeholder="Enter RePassword"
                        onChange={handleChange}
                        value={formData.confirmPassword}
                        name="confirmPassword"
                        required/>
                </div>
                <div className="form-check mb-3 text-end">
                    <label className="form-check-label">
                        <Link className="text-decoration-none text-warning" to="/login">Đăng nhập</Link>
                    </label>
                </div>
                <div>
                    {error && <p style={{color: 'red'}}>{error}</p>}
                </div>
                <button type="submit" className="btn btn-outline-warning form-control mb-3">Đăng ký</button>
                <button type="submit" className="btn btn-outline-danger form-control">Đăng ký bằng tài khoản google
                </button>
            </form>
        </div>
    )
}

export default RegisterForm;
